mapper.select:
SELECT COUNT(*)
FROM FWK_WAS_INSTANCE
WHERE INSTANCE_ID = #{instanceId}

SELECT INSTANCE_ID AS "instanceId", INSTANCE_NAME AS "instanceName", INSTANCE_DESC AS "instanceDesc", WAS_CONFIG_ID AS "wasConfigId", INSTANCE_TYPE AS "instanceType", IP AS "ip", PORT AS "port", OPER_MODE_TYPE AS "operModeType" FROM ( SELECT i.INSTANCE_ID, i.INSTANCE_NAME, i.INSTANCE_DESC, i.WAS_CONFIG_ID, i.INSTANCE_TYPE, i.IP, i.PORT, i.OPER_MODE_TYPE, ROW_NUMBER() OVER (ORDER BY ${orderColumn} ${orderDir}) AS RN FROM FWK_WAS_INSTANCE i
AND i.INSTANCE_NAME LIKE '%' || #{instanceName} || '%'
AND i.INSTANCE_TYPE = #{instanceType}
AND i.OPER_MODE_TYPE = #{operModeType}
) WHERE RN BETWEEN #{offset} + 1 AND #{offset} + #{limit} ORDER BY RN

SELECT COUNT(*)
FROM FWK_WAS_INSTANCE


        AND INSTANCE_NAME LIKE '%' || #{instanceName} || '%'


        AND INSTANCE_TYPE = #{instanceType}


        AND OPER_MODE_TYPE = #{operModeType}

SELECT INSTANCE_ID AS "instanceId", INSTANCE_NAME AS "instanceName", INSTANCE_DESC AS "instanceDesc", WAS_CONFIG_ID AS "wasConfigId", INSTANCE_TYPE AS "instanceType", IP AS "ip", PORT AS "port", OPER_MODE_TYPE AS "operModeType" FROM FWK_WAS_INSTANCE i
AND i.INSTANCE_NAME LIKE '%' || #{instanceName} || '%'
AND i.INSTANCE_TYPE = #{instanceType}
AND i.OPER_MODE_TYPE = #{operModeType}
ORDER BY ${orderColumn} ${orderDir}
